import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricPrompt
import androidx.fragment.app.FragmentActivity
import android.content.SharedPreferences
import com.google.android.material.dialog.MaterialAlertDialogBuilder

class MainActivity : AppCompatActivity() {

    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo
    private lateinit var sharedPreferences: SharedPreferences

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        sharedPreferences = getSharedPreferences("AppPreferences", MODE_PRIVATE)

        if (isAuthenticated()) {
            bypassLogin()
        } else {
            setupBiometricPrompt()
        }
    }

    private fun setupBiometricPrompt() {
        biometricPrompt = BiometricPrompt(this, ContextCompat.getMainExecutor(this), object : BiometricPrompt.AuthenticationCallback() {
            override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                super.onAuthenticationError(errorCode, errString)
                MaterialAlertDialogBuilder(this@MainActivity)
                    .setTitle("Oops!")
                    .setMessage("There was a problem with the authentication. Please try again.")
                    .setPositiveButton("Retry") { _, _ ->
                        authenticate()
                    }
                    .show()
            }

            override fun onAuthenticationFailed() {
                super.onAuthenticationFailed()
                MaterialAlertDialogBuilder(this@MainActivity)
                    .setTitle("Oops!")
                    .setMessage("The fingerprint doesn't match our records. Please try again.")
                    .setPositiveButton("Retry") { _, _ ->
                        authenticate()
                    }
                    .show()
            }

            override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                super.onAuthenticationSucceeded(result)
                storeAuthenticatedFlag(true)
                bypassLogin()
            }
        })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Authenticate")
            .setSubtitle("Please authenticate using your fingerprint to access the app.")
            .setNegativeButtonText("Use password")
            .build()

        MaterialAlertDialogBuilder(this)
            .setTitle("Biometric Authentication Required")
            .setMessage("This app requires biometric authentication for quick access. Do you want to enable it?")
            .setPositiveButton("Enable") { _, _ ->
                authenticate()
            }
            .show()
    }

    private fun authenticate() {
        biometricPrompt.authenticate(promptInfo)
    }

    private fun storeAuthenticatedFlag(flag: Boolean) {
        val editor = sharedPreferences.edit()
        editor.putBoolean("IS_AUTHENTICATED", flag)
        editor.apply()
    }

    private fun isAuthenticated(): Boolean {
        return sharedPreferences.getBoolean("IS_AUTHENTICATED", false)
    }

    private fun bypassLogin() {
        // Logic to bypass login screen
        finish()
    }
}